# frozen_string_literal: true

# nodoc: Autogenerated
class ApplicationController < ActionController::Base
  include BotChallengePage::Controller

  layout :determine_layout

  def determine_layout
    if use_requests_redesign?
      'application_redesign'
    else
      'application'
    end
  end

  # Prevent CSRF attacks by raising an exception.
  # For APIs, you may want to use :null_session instead.
  protect_from_forgery with: :exception

  rescue_from CanCan::AccessDenied, with: :rescue_can_can

  def current_user
    @current_user ||= request.env['warden']&.user&.user_object || User.new
  end

  def current_user?
    current_user.sunetid.present?
  end

  def request_feature_flags
    @request_feature_flags ||= cookies[:feature_flags].to_s.split(',').map(&:strip)
  end

  def use_requests_redesign?
    Settings.features.requests_redesign || request_feature_flags.include?('requests_redesign')
  end

  helper_method :current_user, :current_user?, :sso_user?, :request_feature_flags, :use_requests_redesign?

  private

  def sso_user?
    current_user.sso_user?
  end

  def rescue_can_can(exception)
    logger.debug { "Access denied on #{exception.action} #{exception.subject.inspect}" }
    render status: :forbidden, plain: 'Access to this resource is denied.'
  end

  def redirect_after_action
    if params[:referrer]
      redirect_to post_action_redirect_url
    else
      redirect_back_or_to(root_url)
    end
  end

  def post_action_redirect_url
    params[:referrer].presence || root_url
  end
end
